def asal_sayıları_bul(limit):
    asal = [True] * (limit + 1)
    asal[0] = asal[1] = False

    for i in range(2, int(limit**0.5) + 1):
        if asal[i]:
            for j in range(i*i, limit + 1, i):
                asal[j] = False

    asal_sayılar = [i for i, is_asal in enumerate(asal) if is_asal]
    return asal_sayılar

if __name__ == '__main__':
    limit = int(input("Bir sınır girin: "))
    asal_sayılar = asal_sayıları_bul(limit)
    print("Sınıra kadar asal sayılar:", asal_sayılar)
